-- group-anagrams: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def groupAnagrams(self, strs: List[str]) -> List[List[str]]:
        groups = {}
        for word in strs:
            key = [0] * 26
            for ch in word:
                key[ord(ch) - ord(''a'')] += 1
            t = tuple(key)
            if t not in groups:
                groups[t] = []
            groups[t].append(word)
        result = [sorted(g) for g in groups.values()]
        result.sort(key=lambda g: g[0])
        return result
'
 WHERE problem_id = 'group-anagrams' AND approach_number = 1;

