-- subsets: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def subsets(self, nums: List[int]) -> List[List[int]]:
        result = []
        path = []
        def dfs(i):
            if i == len(nums):
                result.append(path.copy())
                return
            path.append(nums[i])
            dfs(i + 1)
            path.pop()
            dfs(i + 1)
        dfs(0)
        result = [sorted(s) for s in result]
        result.sort(key=lambda s: (len(s), s))
        return result
'
 WHERE problem_id = 'subsets' AND approach_number = 1;

