-- word-search-ii: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def findWords(self, board: List[List[str]], words: List[str]) -> List[str]:
        root = {}
        for w in words:
            node = root
            for ch in w:
                node = node.setdefault(ch, {})
            node[''$''] = w
        rows, cols = len(board), len(board[0])
        result = []
        def dfs(r, c, node):
            ch = board[r][c]
            child = node.get(ch)
            if not child:
                return
            if ''$'' in child:
                result.append(child[''$''])
                del child[''$'']
            board[r][c] = ''#''
            for dr, dc in ((1,0),(-1,0),(0,1),(0,-1)):
                nr, nc = r + dr, c + dc
                if 0 <= nr < rows and 0 <= nc < cols and board[nr][nc] != ''#'':
                    dfs(nr, nc, child)
            board[r][c] = ch
        for r in range(rows):
            for c in range(cols):
                dfs(r, c, root)
        return sorted(result)
'
 WHERE problem_id = 'word-search-ii' AND approach_number = 1;

