-- move-zeroes: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def moveZeroes(self, nums: List[int]) -> List[int]:
        slow = 0
        for fast in range(len(nums)):
            if nums[fast] != 0:
                nums[slow], nums[fast] = nums[fast], nums[slow]
                slow += 1
        return nums
'
 WHERE problem_id = 'move-zeroes' AND approach_number = 1;

-- sort-colors: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def sortColors(self, nums: List[int]) -> List[int]:
        low, mid, high = 0, 0, len(nums) - 1
        while mid <= high:
            if nums[mid] == 0:
                nums[low], nums[mid] = nums[mid], nums[low]
                low += 1
                mid += 1
            elif nums[mid] == 1:
                mid += 1
            else:
                nums[mid], nums[high] = nums[high], nums[mid]
                high -= 1
        return nums
'
 WHERE problem_id = 'sort-colors' AND approach_number = 1;

-- rotate-image: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def rotate(self, matrix: List[List[int]]) -> List[List[int]]:
        n = len(matrix)
        for i in range(n):
            for j in range(i + 1, n):
                matrix[i][j], matrix[j][i] = matrix[j][i], matrix[i][j]
        for row in matrix:
            row.reverse()
        return matrix
'
 WHERE problem_id = 'rotate-image' AND approach_number = 1;

