-- meeting-rooms: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def minMeetingRooms(self, intervals: List[List[int]]) -> int:
        if not intervals:
            return 0
        starts = sorted(i[0] for i in intervals)
        ends = sorted(i[1] for i in intervals)
        rooms = 0
        max_rooms = 0
        e = 0
        for s in starts:
            if s < ends[e]:
                rooms += 1
                if rooms > max_rooms:
                    max_rooms = rooms
            else:
                e += 1
        return max_rooms
'
 WHERE problem_id = 'meeting-rooms' AND approach_number = 1;

-- non-overlapping-intervals: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def eraseOverlapIntervals(self, intervals: List[List[int]]) -> int:
        if not intervals:
            return 0
        intervals.sort(key=lambda x: x[1])
        kept = 1
        end = intervals[0][1]
        for i in range(1, len(intervals)):
            if intervals[i][0] >= end:
                kept += 1
                end = intervals[i][1]
        return len(intervals) - kept
'
 WHERE problem_id = 'non-overlapping-intervals' AND approach_number = 1;

-- encode-decode-strings: solution code
UPDATE public."PGcode_solution_approaches"
   SET code_python = 'class Solution:
    def encode(self, strs: List[str]) -> str:
        return ''''.join(f"{len(w)}#{w}" for w in strs)

    def decode(self, s: str) -> List[str]:
        result = []
        i = 0
        while i < len(s):
            j = i
            while s[j] != ''#'':
                j += 1
            length = int(s[i:j])
            result.append(s[j + 1 : j + 1 + length])
            i = j + 1 + length
        return result

    def solve(self, strs: List[str]) -> List[str]:
        return self.decode(self.encode(strs))
'
 WHERE problem_id = 'encode-decode-strings' AND approach_number = 1;

